          updatedWeeksAtCurrentLevel = 0; // Reset weeks at new level
          updatedConsecutiveMissedWeeks = 0; // Reset missed weeks counter
          setStreak(0);
          setWeeksAtCurrentLevel(0);
          setConsecutiveMissedWeeks(0);
          setCurrentLevel(downgradedLevel);
        } else {
